import React, { useEffect, useState } from 'react';
import { Box, Typography, Paper, List, ListItem, ListItemText, Chip } from '@mui/material';
import { useVoiceControl } from '../context/VoiceControlContext';
import apiService from '../services/apiService';

const FriendsPage = () => {
  const { speakFeedback } = useVoiceControl();
  const [friends, setFriends] = useState([]);

  useEffect(() => {
    speakFeedback('Friends page loaded.');
    // Placeholder: In future, fetch from a real friends API.
    // For now, reuse collaboration invites/users if available.
    (async () => {
      try {
        const invites = await apiService.getMyCollaborationInvites?.();
        const mapped = (invites?.invites || []).map((i) => ({ id: i.from_user_id, name: i.from_user_name || 'Teammate' }));
        setFriends(mapped);
      } catch {
        setFriends([]);
      }
    })();
  }, []);

  return (
    <Box sx={{ p: 3, maxWidth: 900, mx: 'auto' }}>
      <Typography variant="h4" gutterBottom>Friends</Typography>
      <Paper sx={{ p: 2 }}>
        {friends.length === 0 ? (
          <Typography color="text.secondary">No friends yet. Collaboration invites will appear here later.</Typography>
        ) : (
          <List>
            {friends.map((f) => (
              <ListItem key={f.id} secondaryAction={<Chip label="Online" size="small" color="success" />}>
                <ListItemText primary={f.name} secondary={f.id} />
              </ListItem>
            ))}
          </List>
        )}
      </Paper>
    </Box>
  );
};

export default FriendsPage;
